import{c as a,Q as t,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const c=JSON.parse('{"title":"The Rundown AI — 2026-04-16","description":"","frontmatter":{"title":"The Rundown AI — 2026-04-16","date":"2026-04-16T00:00:00.000Z","source":"The Rundown AI","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-04/2026-04-16-the-rundown-ai.md","filePath":"research/ai-news/2026-04/2026-04-16-the-rundown-ai.md","lastUpdated":1779898012000}'),o={name:"research/ai-news/2026-04/2026-04-16-the-rundown-ai.md"};function s(i,e,p,m,l,u){return t(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="🗞️-the-rundown-ai-—-2026-04-16" tabindex="-1">🗞️ The Rundown AI — 2026-04-16 <a class="header-anchor" href="#🗞️-the-rundown-ai-—-2026-04-16" aria-label="Permalink to &quot;🗞️ The Rundown AI — 2026-04-16&quot;">​</a></h1><blockquote><p>每日 AI 產業動態，通俗易懂、密度高 來源：<a href="https://rss.beehiiv.com/feeds/2R3C6Bt5wj.xml" target="_blank" rel="noreferrer">The Rundown AI</a></p></blockquote><hr><h2 id="allbirds-ditches-sneakers-for-ai-compute" tabindex="-1"><a href="https://www.therundown.ai/p/allbirds-ditches-sneakers-for-ai-compute" target="_blank" rel="noreferrer">Allbirds ditches sneakers for AI compute</a> <a class="header-anchor" href="#allbirds-ditches-sneakers-for-ai-compute" aria-label="Permalink to &quot;[Allbirds ditches sneakers for AI compute](https://www.therundown.ai/p/allbirds-ditches-sneakers-for-ai-compute)&quot;">​</a></h2><p><em>🗞️ The Rundown AI | 2026-04-16</em></p><p><a href="./">Read Online</a> | <a href="https://www.therundown.ai/subscribe?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=allbirds-ditches-sneakers-for-ai-compute" target="_blank" rel="noreferrer">Sign Up</a> | <a href="https://therundownai.typeform.com/to/kraZ1TSO?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=allbirds-ditches-sneakers-for-ai-compute" target="_blank" rel="noreferrer">Advertise</a></p><p><a href="https://cal.com/unwrap/quick-connect?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=allbirds-ditches-sneakers-for-ai-compute" target="_blank" rel="noreferrer"></a></p><p>Good morning, AI enthusiasts. CEOs love to predict that all companies will eventually become AI companies. It’s doubtful any of them had “sustainable-sneaker-brand pivots to AI compute” in mind.</p><p>Allbirds, a $4B wool sneaker darling at its IPO peak, just closed a $50M financing deal to become a GPU-rental shop — sending the stock up 600%+ in a single day and taking the crown for the wildest AI pivot of the year.</p><p>In today’s AI rundown:</p><p>Allbirds ditches sneakers for AI compute</p><p>Gemini lands on Mac with native desktop app</p><p>Audit business with Notion&#39;s built-in Claude agents</p><p>Snap cuts 1,000 jobs on AI productivity boosts</p><p>4 new AI tools, community workflows, and more</p><p>LATEST DEVELOPMENTS</p><p>ALLBIRDS</p><p>👟 <a href="https://ir.allbirds.com/news-releases/news-release-details/allbirds-inc-executes-50m-convertible-financing-facility?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=allbirds-ditches-sneakers-for-ai-compute" target="_blank" rel="noreferrer">Allbirds ditches sneakers for AI compute</a></p><p>Image source: Lovart / The Rundown</p><p>The Rundown: Allbirds just <a href="https://ir.allbirds.com/news-releases/news-release-details/allbirds-inc-executes-50m-convertible-financing-facility?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=allbirds-ditches-sneakers-for-ai-compute" target="_blank" rel="noreferrer">announced</a> a $50M financing deal to reinvent itself as &quot;NewBird AI&quot;, converting the gutted footwear company into a GPU rental business and sending the stock up over 600% on the pivot.</p><p>The details:</p><p>Allbirds initially sold its brand assets to American Exchange Group in March for $39M, a fall from the company’s $4B IPO peak in 2021.</p><p>The AI compute move sent shares of $BIRD from $3 to over $20, lifting a market cap that closed Tuesday at just $22M.</p><p>The company said the $50M deal will fund GPU purchases to launch a GPU-as-a-Service business, renting out AI compute under long-term contracts.</p><p>Shareholders will also vote next month to strip Allbirds&#39; &#39;public benefit&#39; status, formally ending the company&#39;s sustainable-footwear mission.</p><p>Why it matters: Many CEOs love to say every company will eventually be an AI company, but gutting a business for parts and retooling it as a GPU rental probably isn&#39;t what they had in mind. Allbirds is running the same move that blockchain rebrands used to revive dying tickers, this time with a compute crunch giving the pitch cover.</p><p>TOGETHER WITH UNWRAP</p><p>⚡ <a href="https://cal.com/unwrap/quick-connect?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=allbirds-ditches-sneakers-for-ai-compute" target="_blank" rel="noreferrer">See how Perplexity automates customer feedback</a></p><p><a href="https://cal.com/unwrap/quick-connect?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=allbirds-ditches-sneakers-for-ai-compute" target="_blank" rel="noreferrer"></a></p><p>The Rundown: Unwrap’s customer intelligence platform pulls all your feedback (surveys, reviews, support tickets, social comments, etc.) into one view, and then uses AI and NLP to surface actionable insights and deliver them straight to your inbox.</p><p>With Unwrap, you get:</p><p>All customer feedback automatically categorized</p><p>Query feedback using Unwrap Assistant, or in your favorite tools via MCP</p><p>Real-time alerts from feedback as they arise, and a clear view of customer sentiment</p><p>A platform trusted and tested at scale by DoorDash, Stripe, Clay, lululemon, WHOOP, and more</p><p>Unwrap is offering a trial of its tools to Rundown AI subscribers! <a href="https://cal.com/unwrap/quick-connect?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=allbirds-ditches-sneakers-for-ai-compute" target="_blank" rel="noreferrer">Just grab a time with the team to get set up</a>.</p><p>GOOGLE</p><p>🖥️ <a href="https://blog.google/innovation-and-ai/products/gemini-app/gemini-app-now-on-mac-os/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=allbirds-ditches-sneakers-for-ai-compute" target="_blank" rel="noreferrer">Gemini lands on Mac with native desktop app</a></p><p>Image source: Google</p><p>The Rundown: Google just <a href="https://blog.google/innovation-and-ai/products/gemini-app/gemini-app-now-on-mac-os/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=allbirds-ditches-sneakers-for-ai-compute" target="_blank" rel="noreferrer">rolled out</a> a new Mac app for its Gemini assistant, giving the AI a native desktop chatbot experience, coming a year after rivals like ChatGPT and Claude made their moves.</p><p>The details:</p><p>The app launches via Option+Space and offers screen-sharing, Drive and Photos file access, and Nano Banana image and Veo video generation.</p><p>The Gemini app trails in agentic abilities, remaining a chat-first assistant, while Claude and ChatGPT can directly execute tasks on users&#39; machines.</p><p>Google calls this release “just the beginning” of its desktop assistant push, with more features teased for the coming months.</p><p>The company also <a href="https://search.google/google-app/desktop/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=allbirds-ditches-sneakers-for-ai-compute" target="_blank" rel="noreferrer">rolled out</a> a Windows app that bundles Gemini and Google Lens into a search bar, but shipped English-only versus the Mac&#39;s global rollout.</p><p>Why it matters: The desktop is becoming a fight for muscle memory, with native apps unlocking stickiness as a user’s daily driver. Gemini is showing up a year late, which follows a trend of losing to Claude / ChatGPT on accessibility and ease of use, even more than performance — but Google’s distribution can make up for things in no time.</p><p>AI TRAINING</p><p>📋 <a href="https://app.therundown.ai/guides/how-to-audit-your-business-with-notions-built-in-claude-agents?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=allbirds-ditches-sneakers-for-ai-compute" target="_blank" rel="noreferrer">Audit business with Notion&#39;s built-in Claude agents</a></p><p><a href="https://app.therundown.ai/guides/how-to-audit-your-business-with-notions-built-in-claude-agents?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=allbirds-ditches-sneakers-for-ai-compute" target="_blank" rel="noreferrer"></a></p><p>The Rundown: In this guide, you will learn how to use Notion&#39;s prebuilt Claude-powered AI agents and use them to audit your workspace for efficiency. We found the audits to be thorough and well-formatted, like a report you’d get from a real consultant.</p><p>Step-by-step:</p><p>In <a href="https://www.notion.so/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=allbirds-ditches-sneakers-for-ai-compute" target="_blank" rel="noreferrer">Notion</a>, go to Notion AI in the sidebar, click the + button &gt; browse <a href="https://notion.com/custom-agent-templates?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=allbirds-ditches-sneakers-for-ai-compute" target="_blank" rel="noreferrer">templates</a>, and install the <a href="https://www.notion.com/custom-agent-templates/workspace-auditor?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=allbirds-ditches-sneakers-for-ai-compute" target="_blank" rel="noreferrer">Business Workspace Auditor</a></p><p>Give the agent access to relevant pages and workspaces, and hit the save button. Then, open it and @ mention the pages/databases you want reviewed</p><p>Just say: “Audit this page,” and it will work, running its preconfigured audit and creating an issue report with severity and a recommended fix for each item</p><p>If you give the agent edit permissions on the page/database it audited, you can tell it to make the recommended fixes itself, as well</p><p>Pro tip: This flow works for other templates, too. Try Business Process Audit to map and diagnose a workflow, or Task Triager to route a brain-dump to your Tasks database.</p><p>PRESENTED BY POSTMAN</p><p>💸 <a href="https://fandf.co/4rXfgxK?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=allbirds-ditches-sneakers-for-ai-compute" target="_blank" rel="noreferrer">The ROI of AI engineering</a></p><p><a href="https://fandf.co/4rXfgxK?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=allbirds-ditches-sneakers-for-ai-compute" target="_blank" rel="noreferrer"></a></p><p>The Rundown: Postman’s cost savings analysis evaluates six engineering workflows to prove how AI-native development delivers measurable ROI by eliminating manual API tasks and external tool friction.</p><p>In this report, you’ll explore:</p><p>Measurable ROI of actual time and money saved per team</p><p>Why natively integrated, built-in AI outperforms external tools</p><p>Before-and-after benchmarks engineering leads can use to measure impact</p><p><a href="https://fandf.co/4rXfgxK?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=allbirds-ditches-sneakers-for-ai-compute" target="_blank" rel="noreferrer">Read Postman&#39;s full cost savings analysis</a>.</p><p>SNAP</p><p>✂️ <a href="https://newsroom.snap.com/organizational-changes-at-snap?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=allbirds-ditches-sneakers-for-ai-compute" target="_blank" rel="noreferrer">Snap cuts 1,000 jobs on AI productivity boosts</a></p><p>Image source: Snap</p><p>The Rundown: Snap just <a href="https://newsroom.snap.com/organizational-changes-at-snap?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=allbirds-ditches-sneakers-for-ai-compute&amp;_bhlid=3e19a52bd938f7e0244839842e1b3a0020ee8f8d" target="_blank" rel="noreferrer">announced</a> layoffs of 1,000 employees representing 16% of its workforce, with CEO Evan Spiegel attributing the reduction to AI efficiency rather than shareholder pressure.</p><p>The details:</p><p>Snap is swapping traditional teams for small AI-augmented pods, with the tech writing 65% of new code and fielding 1M+ monthly queries at the company.</p><p>Spiegel said AI’s advances “enable our teams to reduce repetitive work, increase velocity, and better support our community, partners, &amp; advertisers.&quot;</p><p>The social media giant’s stock rose 7-9% on the news but remains down 30% YTD, with the plan targeting $500M in annual cost savings by the end of 2026.</p><p>Block <a href="https://x.com/jack/status/2027129697092731343?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=allbirds-ditches-sneakers-for-ai-compute" target="_blank" rel="noreferrer">opened</a> 2026&#39;s AI layoff wave in February with 4,000 cuts (40% of staff), and 70K+ tech jobs have been <a href="https://www.techradar.com/pro/nearly-80-000-tech-workers-have-already-lost-their-jobs-in-2026-and-ai-impact-means-more-could-be-to-come?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=allbirds-ditches-sneakers-for-ai-compute" target="_blank" rel="noreferrer">erased</a> across companies this year.</p><p>Why it matters: Wall Street is rewarding two AI moves above all else right now: wholesale pivots (Allbirds) and AI-driven layoffs. With the tech sector’s sentiment at an all-time low and anxiety over job loss rising, the disconnect between what markets cheer and what workers fear is only widening.</p><p>QUICK HITS</p><p>🛠️ <a href="https://www.rundown.ai/tools?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=allbirds-ditches-sneakers-for-ai-compute" target="_blank" rel="noreferrer">Trending AI Tools</a></p><p>💻 <a href="https://www.rundown.ai/tools/gemini-for-mac?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=allbirds-ditches-sneakers-for-ai-compute" target="_blank" rel="noreferrer">Gemini for Mac</a> - Google&#39;s new native macOS app for Gemini</p><p>🌎 <a href="http://www.rundown.ai/tools/lyra-2-0?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=allbirds-ditches-sneakers-for-ai-compute" target="_blank" rel="noreferrer">Lyra 2.0</a> - NVIDIA&#39;s AI to turn text, camera paths into explorable 3D scenes</p><p>🎧 <a href="http://www.rundown.ai/tools/gemini-3-1-flash-tts?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=allbirds-ditches-sneakers-for-ai-compute" target="_blank" rel="noreferrer">Gemini 3.1 Flash TTS</a> - Google&#39;s speech model for 70+ languages</p><p>🎆 <a href="https://www.rundown.ai/tools/ernie-image?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=allbirds-ditches-sneakers-for-ai-compute" target="_blank" rel="noreferrer">Ernie Image</a> - Baidu’s powerful new open-weight text-to-image model</p><p>📰 <a href="https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=allbirds-ditches-sneakers-for-ai-compute" target="_blank" rel="noreferrer">Everything else in AI today</a></p><p>ASAPP’s Nirmal Mukhi and special guest Kate Leggett <a href="https://www.asapp.com/webinars/redesigning-the-service-role-for-the-ai-agent-era?utm_campaign=21867577-nurture&amp;utm_medium=email&amp;utm_source=therundownai&amp;utm_content=rundown-forrester-demand" target="_blank" rel="noreferrer">analyze</a> recent Forrester research on planning, staffing, and operationalizing the new roles AI agents bring to the customer service workforce.*</p><p>Adobe <a href="https://news.adobe.com/news/2026/04/adobe-new-creative-agent?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=allbirds-ditches-sneakers-for-ai-compute" target="_blank" rel="noreferrer">debuted</a> Firefly AI Assistant, its push into &quot;agentic creativity&quot;, with a chat that runs multi-app creative workflows across Photoshop, Premiere, Lightroom, and Firefly.</p><p>Google <a href="https://blog.google/innovation-and-ai/models-and-research/gemini-models/gemini-3-1-flash-tts/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=allbirds-ditches-sneakers-for-ai-compute" target="_blank" rel="noreferrer">released</a> Gemini 3.1 Flash text-to-speech, a new model with audio tags that can steer tone, pace, and accent, currently #2 on Artificial Analysis’s TTS leaderboard.</p><p>GPT-5.4 Pro <a href="https://x.com/jdlichtman/status/2044298382852927894?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=allbirds-ditches-sneakers-for-ai-compute" target="_blank" rel="noreferrer">produced</a> a proof for a 60-year-old math problem, with mathematician Jared Lichtman saying it found a path humans overlooked for nearly a century.</p><p>Anthropic is <a href="https://www.theinformation.com/articles/anthropic-changes-pricing-bill-firms-based-ai-use-amid-compute-crunch?rc=a8sc5q&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=allbirds-ditches-sneakers-for-ai-compute" target="_blank" rel="noreferrer">switching</a> Claude Enterprise pricing to charge businesses based on token consumption, a shift that could significantly raise bills for power users.</p><p>*Sponsored Listing</p><p>COMMUNITY</p><p>🤝 <a href="https://docs.google.com/forms/d/e/1FAIpQLSfH4UPzu72HTpdb08Qlm-0dLwKJIjdcAwCcAvVywcHD6mwKig/viewform?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=allbirds-ditches-sneakers-for-ai-compute" target="_blank" rel="noreferrer">Community AI workflows</a></p><p>Every newsletter, we showcase how a reader is using AI to work smarter, save time, or make life easier.</p><p>Today’s workflow comes from reader Kerstin R. in London, UK:</p><p>&quot;I have a lot of clothes I no longer need. And while I&#39;ve donated some, there are some higher ticket items in there I&#39;ve been looking to sell. But getting all of the items listed on a secondhand sales platform seemed very time-consuming and daunting.</p><p>So I&#39;ve built my own system, where all I need to do is take some photos of each item, add some keywords, brand, size, and price, submit it via an Airtable form directly from my phone, and Claude creates all the copy for each text field I need from headline to description to make it a super compelling and optimised listing.</p><p>Claude also helps me gauge pricing based on existing listings on the platform. Huge time saver and I can finally get some money back from things I no longer need.&quot;</p><p>How do you use AI? Tell us <a href="https://docs.google.com/forms/d/e/1FAIpQLSfH4UPzu72HTpdb08Qlm-0dLwKJIjdcAwCcAvVywcHD6mwKig/viewform?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=allbirds-ditches-sneakers-for-ai-compute" target="_blank" rel="noreferrer">here</a>.</p><p>🎓 <a href="https://app.therundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=allbirds-ditches-sneakers-for-ai-compute" target="_blank" rel="noreferrer">Highlights: News, Guides &amp; Events</a></p><p>Read our last AI newsletter: <a href="https://www.rundown.ai/articles/openai-gpt-5-4-cyber-rejects-mythos-playbook?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=allbirds-ditches-sneakers-for-ai-compute" target="_blank" rel="noreferrer">OAI’s GPT-5.4-Cyber rejects Mythos playbook</a></p><p>Read our last Tech newsletter: <a href="https://tech.therundown.ai/p/meta-closing-in-on-google-ad-crown?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=allbirds-ditches-sneakers-for-ai-compute" target="_blank" rel="noreferrer">Meta closing in on Google’s ad crown</a></p><p>Read our last Robotics newsletter: <a href="https://robotnews.therundown.ai/p/unitree-cheapest-humanoid-goes-global?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=allbirds-ditches-sneakers-for-ai-compute" target="_blank" rel="noreferrer">Unitree’s cheapest humanoid goes global</a></p><p>Today’s AI tool guide: <a href="https://app.therundown.ai/guides/how-to-audit-your-business-with-notions-built-in-claude-agents?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=allbirds-ditches-sneakers-for-ai-compute" target="_blank" rel="noreferrer">Audit business with Notion&#39;s built-in Claude agents</a></p><p>See you soon,</p><p>Rowan, Joey, Zach, Shubham, and Jennifer — the humans behind The Rundown</p><hr>',104)])])}const h=a(o,[["render",s]]);export{c as __pageData,h as default};
